// Static binary driver — generated by partial_reconfiguration
// Single-threaded, multi-process architecture

#include "dpi_shm_channel.h"
#include "barrier_sync.h"
#include "shm_mailbox.h"

#include <verilated.h>
#include "Vweird_clock_static.h"
#include "signal_access.h"

#include <cstring>
#include <iostream>
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>

// Required by Verilator
double sc_time_stamp() { return 0; }

#define NUM_PARTITIONS 1

static Vweird_clock_static* static_model = nullptr;
static VerilatedContext* static_ctx = nullptr;
static ShmMailbox* mailbox = nullptr;
static ShmBarrier* barrier = nullptr;

// Partition channel bases (exported for signal_access.h)
void* g_partition_bases[NUM_PARTITIONS];
static ShmPartitionHeader* g_partition_headers[NUM_PARTITIONS];
static size_t g_partition_sizes[NUM_PARTITIONS];

static void swap_channels() {
    for (int p = 0; p < NUM_PARTITIONS; p++) {
        void* base = g_partition_bases[p];
        ShmPartitionHeader* hdr = g_partition_headers[p];
        uint32_t T = hdr->num_to_rm;
        uint32_t F = hdr->num_from_rm;
        for (uint32_t i = 0; i < T; i++) {
            ShmPort* ob = shm_to_rm_outbox(base, i);
            ShmPort* ib = shm_to_rm_inbox(base, i);
            ib->data = ob->data;
            ib->valid = ob->valid;
            ob->valid = 0;
        }
        for (uint32_t i = 0; i < F; i++) {
            ShmPort* ob = shm_from_rm_outbox(base, T, i);
            ShmPort* ib = shm_from_rm_inbox(base, T, i);
            ib->data = ob->data;
            ib->valid = ob->valid;
            ob->valid = 0;
        }
    }
}

static int reconfig_partition = -1;

static void process_commands() {
    if (mailbox->cmd == CMD_NOOP) return;

    switch (mailbox->cmd) {
    case CMD_READ: {
        uint64_t val = 0;
        if (mailbox->target == TARGET_STATIC) {
            val = read_static_port(static_model, mailbox->port_idx);
        }
        else if (mailbox->target == 1) {
            val = read_rp_dummy_port(mailbox->port_idx);
        }
        mailbox->read_value = val;
        mailbox->cmd = CMD_NOOP;
        break;
    }
    case CMD_WRITE: {
        if (mailbox->target == TARGET_STATIC) {
            write_static_port(static_model, mailbox->port_idx, mailbox->write_value);
        }
        else if (mailbox->target == 1) {
            write_rp_dummy_port(mailbox->port_idx, mailbox->write_value);
        }
        mailbox->cmd = CMD_NOOP;
        break;
    }
    case CMD_RECONFIG: {
        int part_id = mailbox->target - 1;
        if (part_id >= 0 && part_id < NUM_PARTITIONS) {
            // Set quit flag for target partition — RM will exit after current cycle
            shm_store32(&g_partition_headers[part_id]->quit, 1);
            // Clear overrides
            void* base = g_partition_bases[part_id];
            for (uint32_t i = 0; i < g_partition_headers[part_id]->num_to_rm; i++) {
                ShmPortOverride* ovr = shm_to_rm_override(base, i);
                shm_store32(&ovr->active, 0);
            }
            reconfig_partition = part_id;
        }
        // Don't set cmd=NOOP yet — Python waits until reconfig completes
        break;
    }
    case CMD_QUIT:
        mailbox->cmd = CMD_NOOP;
        break;
    }
}

static void* mmap_file(const char* path, size_t expected_size, int* fd_out) {
    int fd = open(path, O_RDWR);
    if (fd < 0) { perror(path); return nullptr; }
    struct stat st;
    fstat(fd, &st);
    size_t sz = (expected_size > 0) ? expected_size : (size_t)st.st_size;
    void* ptr = mmap(nullptr, sz, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    if (ptr == MAP_FAILED) { perror("mmap"); close(fd); return nullptr; }
    if (fd_out) *fd_out = fd; else close(fd);
    return ptr;
}

int main(int argc, char** argv) {
    const char* shm_dir = nullptr;
    for (int i = 1; i < argc; i++) {
        if (std::string(argv[i]) == "--shm-dir" && i + 1 < argc)
            shm_dir = argv[++i];
    }
    if (!shm_dir) { std::cerr << "Error: --shm-dir required" << std::endl; return 1; }

    std::string dir(shm_dir);

    // Open Python mailbox
    int mbox_fd = -1;
    mailbox = (ShmMailbox*)mmap_file((dir + "/cmd_mailbox.shm").c_str(), SHM_MAILBOX_SIZE, &mbox_fd);
    if (!mailbox) return 1;

    // Open barrier
    int barrier_fd = -1;
    barrier = (ShmBarrier*)mmap_file((dir + "/barrier.shm").c_str(), 4096, &barrier_fd);
    if (!barrier) return 1;

    // Open partition channels
    int ch_fds[NUM_PARTITIONS];
    for (int p = 0; p < NUM_PARTITIONS; p++) {
        std::string path = dir + "/partition_" + std::to_string(p) + ".shm";
        g_partition_bases[p] = mmap_file(path.c_str(), 0, &ch_fds[p]);
        if (!g_partition_bases[p]) return 1;
        g_partition_headers[p] = shm_header(g_partition_bases[p]);
        struct stat st; fstat(ch_fds[p], &st);
        g_partition_sizes[p] = st.st_size;
    }

    // Create static region model
    static_ctx = new VerilatedContext;
    static_model = new Vweird_clock_static(static_ctx);

    mailbox->sim_status = SIM_STATUS_RUNNING;
    mailbox->cycle_count = 0;

    // Initialize local barrier sense
    uint32_t local_sense = __atomic_load_n(&barrier->sense, __ATOMIC_ACQUIRE);

    // Main simulation loop
    uint64_t cycle = 0;
    bool quit_global = false;

    while (!quit_global) {
        // Phase 1: negedge eval
        static_model->sys_input = 0;
        static_model->eval();
        barrier_wait(barrier, &local_sense);  // 1: negedge done

        // Phase 2: swap channels + process commands
        swap_channels();
        process_commands();
        if (mailbox->cmd == CMD_QUIT) { quit_global = true; }
        barrier_wait(barrier, &local_sense);  // 2: swap done

        // Phase 3: posedge eval
        static_model->sys_input = 1;
        static_model->eval();
        barrier_wait(barrier, &local_sense);  // 3: posedge done

        cycle++;
        mailbox->cycle_count = cycle;

        // Handle pending reconfiguration (pause-based V1)
        // After barrier 3, old RM will check quit and exit.
        // Other RMs will arrive at barrier 1 of next cycle and wait.
        // We wait here for the new RM to signal ready.
        if (reconfig_partition >= 0) {
            ShmPartitionHeader* hdr = g_partition_headers[reconfig_partition];
            // Wait for new RM to be ready
            while (!shm_load32(&hdr->rm_ready)) {
                // spin — Python starts new RM which sets rm_ready
            }
            // Clear reconfig state
            shm_store32(&hdr->quit, 0);
            shm_store32(&hdr->rm_ready, 0);
            reconfig_partition = -1;
            mailbox->cmd = CMD_NOOP;  // Signal completion to Python
        }
    }

    // Signal all RMs to quit
    for (int p = 0; p < NUM_PARTITIONS; p++)
        shm_store32(&g_partition_headers[p]->quit, 1);

    // Do 3 more barrier rounds so RMs can see quit and exit
    for (int i = 0; i < 3; i++)
        barrier_wait(barrier, &local_sense);

    // Cleanup
    delete static_model;
    delete static_ctx;
    mailbox->sim_status = SIM_STATUS_DONE;
    munmap(mailbox, SHM_MAILBOX_SIZE); close(mbox_fd);
    munmap(barrier, 4096); close(barrier_fd);
    for (int p = 0; p < NUM_PARTITIONS; p++) {
        munmap(g_partition_bases[p], g_partition_sizes[p]);
        close(ch_fds[p]);
    }
    return 0;
}